var defaultUrls = {
  getUserOdpsInfo : '/r/apps/user/getUserOdpsInfo'
};
/**
 *  Context
 */

var Context = {};
Context.appMap = {};
Context.options =  {};
Context.username = '@@username@@';
Context.init = function(opt){
  Context.options = opt;
  var urls = opt.configer(opt);
  Context.initApps(opt, urls);
};
Context.initApps = function(opt, urls){
  var app = opt.app, key, url;
  Context.app = app;
  for(key in defaultUrls){
    url = defaultUrls[key];
    if(!urls[key]){
      urls[key] = url;
    }
  }
  Context.appMap[app] = {
    urls : urls
  };
};
Context.reload = function (env) {
  var options = Context.options;
  Context.init(options);
};
Object.defineProperties(Context, {
  urls : {
    get : function(){
      var app = this.app;
      if(app){
        return this.appMap[app].urls;
      }else{
        return {};
      }
    }
  }
});
exports = module.exports = Context;